func createAgentServices(
	cfg config.Config,
	mgr manager.Manager,
	statusQueue *status.Queue,
) (*agent.NginxUpdaterImpl, error) {
	resetConnChan := make(chan struct{})
	nginxUpdater := agent.NewNginxUpdater(
		cfg.Logger.WithName("nginxUpdater"),
		mgr.GetAPIReader(),
		statusQueue,
		resetConnChan,
		cfg.Plus,
	)

