		"%s.%s.svc",
		cfg.GatewayPodConfig.ServiceName,
		cfg.GatewayPodConfig.Namespace,
	)

	grpcServer := agentgrpc.NewServer(
		cfg.Logger.WithName("agentGRPCServer"),
		grpcServerPort,
		[]func(*grpc.Server){
			nginxUpdater.CommandService.Register,
