			tel.ExporterConfig{
				SpanProvider: tel.CreateOTLPSpanProvider(options...),
			},
			tel.WithGlobalOTelLogger(logger.WithName("otel")),
			tel.WithGlobalOTelErrorHandler(errorHandler),
		)
		if err != nil {
			return nil, fmt.Errorf("cannot create telemetry exporter: %w", err)
